import{_ as a,o as i,i as s,a9 as t}from"./chunks/framework.D47vmB0i.js";const u=JSON.parse('{"title":"Security","description":"Guard CSV exports against spreadsheet formula injection with one option.","frontmatter":{"description":"Guard CSV exports against spreadsheet formula injection with one option."},"headers":[],"relativePath":"guide/security.md","filePath":"guide/security.md","lastUpdated":1781709514000}'),r={name:"guide/security.md"};function n(l,e,o,h,p,d){return i(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h1><h2 id="formula-injection" tabindex="-1">Formula injection <a class="header-anchor" href="#formula-injection" aria-label="Permalink to &quot;Formula injection&quot;">​</a></h2><p>csv-pipe produces RFC 4180-compliant text. By default it does not neutralize values that a spreadsheet application may interpret as a formula (for example a cell beginning with <code>=</code>, <code>+</code>, <code>-</code>, <code>@</code>, a tab, or a carriage return).</p><p>When you export untrusted data for use in spreadsheets, enable the built-in guard:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">stringify</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">([{ note: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;=1+1&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }], { sanitizeFormulas: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> });</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// note</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// &#39;=1+1   (the leading quote makes a spreadsheet show the cell literally)</span></span></code></pre></div><p>It prefixes any string or array cell that begins with a formula character so the value is shown literally. Numbers, booleans, and dates are never altered. The prefix defaults to a single quote and can be changed with <code>formulaPrefix</code>:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">stringify</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">([{ note: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;=1+1&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }], { sanitizeFormulas: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, formulaPrefix: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> });</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// note</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// \\t=1+1   (prefixed with a tab instead of a quote)</span></span></code></pre></div><p>On the parsing side a cell that looks like a formula (for example <code>=1+1</code>) is returned as a plain string; csv-pipe never evaluates it. The guard matters when you re-export parsed, untrusted data, so set <code>sanitizeFormulas</code> on that export.</p><h2 id="resource-safety" tabindex="-1">Resource safety <a class="header-anchor" href="#resource-safety" aria-label="Permalink to &quot;Resource safety&quot;">​</a></h2><p>Parsing holds one record in memory at a time, so the size of the input alone cannot exhaust memory, whether it arrives as a file, an upload, or a network body. Stop early with <code>break</code> or <code>maxRows</code> and csv-pipe releases the source at once, cancelling a Web <code>ReadableStream</code> or closing a Node file handle. See <a href="./parsing-streaming">Streaming and files</a>.</p><h2 id="reporting-a-vulnerability" tabindex="-1">Reporting a vulnerability <a class="header-anchor" href="#reporting-a-vulnerability" aria-label="Permalink to &quot;Reporting a vulnerability&quot;">​</a></h2><p>Please report security issues privately through <a href="https://github.com/martsinlabs/csv-pipe/security/advisories/new" target="_blank" rel="noreferrer">private vulnerability reporting</a> on GitHub, not as a public issue. See the <a href="https://github.com/martsinlabs/csv-pipe/blob/master/SECURITY.md" target="_blank" rel="noreferrer">security policy</a> for details.</p>`,12)])])}const k=a(r,[["render",n]]);export{u as __pageData,k as default};
